import{_ as i,o as r,c as l,a2 as a}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-20（週三）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-20.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-20.md"}'),o={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-20.md"};function n(s,t,e,d,g,h){return r(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="🫘-黃豆追蹤日報-—-2026-05-20-週三" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-20（週三） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-20-週三" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-20（週三）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-20 05:00 TST（2026-05-19 21:00 UTC） 報告類型：每日追蹤 ⚠️ CBOT 期貨時段說明：05:00 TST 週三凌晨 = 17:00 ET 週二，黃豆期貨已收盤</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>查詢時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆 Jul 2026 (ZSN26)</td><td>1,209 USd/Bu</td><td>-3¢ (-0.33%)</td><td>2026-05-19 16:00 ET</td><td>TradingEconomics</td></tr><tr><td>WTI 原油</td><td>~$99-104/桶</td><td>-2%</td><td>2026-05-19</td><td>TradingEconomics</td></tr><tr><td>Brent 原油</td><td>$110.51/桶</td><td>-1.42%</td><td>2026-05-19</td><td>TradingEconomics</td></tr><tr><td>DXY 美元指數</td><td>99.33</td><td>+0.35%</td><td>2026-05-19</td><td>TradingView</td></tr><tr><td>天然氣 Henry Hub</td><td>$2.96/MMBtu</td><td>—</td><td>2026-05-15</td><td>TradingEconomics</td></tr></tbody></table><blockquote><p><strong>查詢時間（TST）</strong>：2026-05-20 05:00</p></blockquote><hr><h2 id="🔍-敘事延續-川習會承諾消化後回調-種植進度大幅領先-—-黃豆小幅回落至-1-209" tabindex="-1">🔍 敘事延續：川習會承諾消化後回調 + 種植進度大幅領先 — 黃豆小幅回落至 1,209 <a class="header-anchor" href="#🔍-敘事延續-川習會承諾消化後回調-種植進度大幅領先-—-黃豆小幅回落至-1-209" aria-label="Permalink to &quot;🔍 敘事延續：川習會承諾消化後回調 + 種植進度大幅領先 — 黃豆小幅回落至 1,209&quot;">​</a></h2><p><strong>本日核心</strong>：CBOT 黃豆 Jul 回落至 1,209 USd/Bu（-0.33%），回吐部分昨日 2.97% 漲幅。川習會 $17B 農業承諾利好已在週一反映，市場等待中國實際採購行動。USDA 種植進度大幅領先（67% vs 五年均值 53%），利空壓力有限。油價回落（WTI 跌至 $99-104）減輕能源成本壓力，但美元走強（DXY 99.33）壓制出口競爭力。</p><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>種植進度</strong>（截至 5/18）：67% 黃豆已播種（前週 48%），高於五年均值 53%</li><li><strong>出芽率</strong>：32% 已出芽</li><li><strong>個別州</strong>： <ul><li>Iowa：60%（前週 60%）</li><li>Nebraska：64%（大幅領先）</li><li>Tennessee：76%（遠超均值）</li><li>Minnesota：51%（大幅領先）</li><li>Ohio：46%（vs 五年均值 35%）</li><li>Indiana：51%（大幅領先）</li><li>Michigan：12%（落後，異常低）</li></ul></li><li><strong>變化</strong>：🟢 <strong>大幅領先</strong> — 67% vs 53% 五年均值，Michigan 為唯一落後州</li><li><strong>分析</strong>：種植順利 → 供應預期增加 → 利空；但 Michigan 落後需關注</li><li><strong>查詢時間</strong>：2026-05-18</li><li>來源：Brownfield Ag News (2026-05-18)、RFD TV (2026-05-18)、OCJ (2026-05-19)</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>CONAB</strong>（5 月）：2025/26 產量 180.13M 噸（+0.5% vs 前估，+5% YoY）</li><li><strong>StoneX</strong>（5 月）：下修至 177.8M 噸（南大河乾旱）</li><li><strong>出口</strong>：CONAB 預測 116M 噸（歷史新高，+7.25% YoY）</li><li><strong>2026/27 展望</strong>：USDA 預估巴西產量 186M 噸（+8M vs 本季）</li><li><strong>巴西農民困境</strong>：低黃豆價格 + 高生產成本 + 弱港口溢價 → 利潤壓縮 → 擴種放緩</li><li><strong>變化</strong>：🟡 無重大變化 — 本季已收割完成，關注下季播種</li><li><strong>查詢時間</strong>：2026-05-19</li><li>來源：CONAB (2026-05)、Caixin Global (2026-05-18)、Farmdocdaily (2026-03)</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>尿素</strong>：$577/噸（+0.79%），月跌 19.07% 但年漲 21.79%</li><li><strong>荷莫茲效應</strong>：全球 ~30% 化肥出口經過海峽，成本持續高檔</li><li><strong>變化</strong>：🟡 成本高檔但月跌 — 短期壓力紓解但長期結構性上升</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)</li></ul><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><ul><li>🔴 <strong>持續封閉但出現轉機信號</strong>：</li><li><strong>川普暗示和平進展</strong>（5/19）：暗示伊朗和平協議可能取得進展，但未提供細節</li><li><strong>海峽現狀</strong>：實質封閉未變，70+ 艘商業船被改道，4 艘被扣押</li><li><strong>巴基斯坦斡旋</strong>：持續居中協調，但伊朗拒絕暫停鈾濃縮</li><li><strong>美中聯合</strong>：雙方同意海峽「必須保持開放」</li><li><strong>對黃豆影響</strong>：油價回落（WTI -2%）→ 能源成本壓力紓解 → 農業成本負擔減輕</li><li><strong>變化</strong>：🟡 <strong>轉機信號增加但未實質改善</strong> — 和平協議進展有限</li><li><strong>查詢時間</strong>：2026-05-19</li><li>來源：Time (2026-05-19)、CBS News (2026-05-19)、Al Arabiya (2026-05-19)</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li>🟡 <strong>承諾已公布但缺乏細節</strong>：</li><li><strong>White House</strong>（5/17）：中國承諾 2026-2028 每年購買 $17B 美國農產品</li><li><strong>額外承諾</strong>（2025/10）：中國承諾每年購買至少 25M 噸美國黃豆</li><li><strong>實際執行情況</strong>：1-3 月中國從美國進口 3.4M 噸黃豆，但後續採購尚未落實</li><li><strong>S&amp;P Global</strong>：年初至今美國對華黃豆銷售年減 48%</li><li><strong>分析</strong>：$17B 承諾 + 25M 噸年度目標是正面信號，但「preliminary」+ 缺乏細節 → 市場觀望</li><li><strong>變化</strong>：🟡 延續前次 — 承諾已公布但等待中國實際行動</li><li><strong>查詢時間</strong>：2026-05-19</li><li>來源：White House (2026-05)、SCMP (2026-05-16)、Caixin Global (2026-05-18)</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub</strong>：$2.96/MMBtu（+2.28%），接近七週高</li><li><strong>EIA 注入</strong>：85 bcf（符合預期），低於去年同期 109 bcf</li><li><strong>變化</strong>：🟡 無重大變化 — 供給偏緊但需求季節性低</li><li><strong>查詢時間</strong>：2026-05-15</li><li>來源：TradingEconomics (2026-05-15)</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><ul><li><strong>變化</strong>：⚪ 本日無重大更新 — 待下季氣候報告</li><li><strong>查詢時間</strong>：2026-05-20</li></ul><h3 id="_8-cbot-價格區間-海運成本" tabindex="-1">8. CBOT 價格區間 + 海運成本 <a class="header-anchor" href="#_8-cbot-價格區間-海運成本" aria-label="Permalink to &quot;8. CBOT 價格區間 + 海運成本&quot;">​</a></h3><ul><li><strong>Jul 2026</strong>：1,209 USd/Bu（-0.33%），從 1,212 小幅回落</li><li><strong>技術面</strong>：支撐 1,180-1,200¢，壓力 1,220-1,240¢</li><li><strong>新作物 Nov</strong>：觸三年新高 &gt;$12/bu（受 WASDE 利多）</li><li><strong>變化</strong>：🟡 <strong>小幅回調</strong> — 川習會承諾利好消化後獲利了結</li><li><strong>查詢時間</strong>：2026-05-19</li><li>來源：TradingEconomics (2026-05-19)、Agrolatam (2026-05)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>Brownfield Ag News (2026-05-18)</strong>：USDA soybean planting 67% through May 18, ahead of 53% five-year average</li><li><strong>Caixin Global (2026-05-18)</strong>：Trump&#39;s China visit stabilizes outlook for US soybean trade deal</li><li><strong>SCMP (2026-05-16)</strong>：China commits $17B/year in US farm goods, but details remain preliminary</li><li><strong>TradingEconomics (2026-05-19)</strong>：Soybeans fell to 1,209 (-0.33%), giving back Monday&#39;s gains</li><li><strong>Agrolatam (2026-05)</strong>：Soybean price rally on US-China trade deal hopes</li></ol><hr><h2 id="📊-情景分析" tabindex="-1">📊 情景分析 <a class="header-anchor" href="#📊-情景分析" aria-label="Permalink to &quot;📊 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>中國 6 月下調關稅 + $17B 實際執行 + 海峽局部重開</td><td>30%</td><td>+8-12%（至 ~1,300-1,360¢）</td><td>需求大增 + 能源成本下降</td></tr><tr><td>海峽持續封閉 + 種植順利 + 中國觀望</td><td>45%</td><td>持平至 -2%（1,180-1,220¢）</td><td>供應充足 vs 能源成本高檔</td></tr><tr><td>中國延遲行動 + 油價因制裁豁免暴跌</td><td>25%</td><td>-3-5%（至 ~1,150-1,180¢）</td><td>美元走強 + 出口競爭力下降</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-19): Soybeans 1,209 (-0.33%), WTI ~$99-104</li><li>Brownfield Ag News (2026-05-18): USDA crop progress 67% planted</li><li>RFD TV (2026-05-18): Soybean planting progress by state</li><li>CONAB (2026-05): Brazil soybean production 180.13M tons</li><li>Caixin Global (2026-05-18): Trump&#39;s China visit stabilizes soybean trade outlook</li><li>SCMP (2026-05-16): China-US farm deal $17B/year scope analysis</li><li>White House (2026-05): Fact sheet — China commits $17B/year in US ag purchases</li><li>Agrolatam (2026-05): Soybean price rally on trade deal hopes</li><li>Farmdocdaily (2026-03): Brazil soybean margins approaching breakeven</li><li>Time (2026-05-19): Trump hints at Iran peace progress</li></ol>',36)])])}const b=i(o,[["render",n]]);export{u as __pageData,b as default};
